+        Window w = s.getOwner();
+        if (w == null) {
+            s.centerOnScreen();
+        } else {
+            // or use JDK-8372530
+            Scene sc = s.getScene();
+            double x = w.getX() + (w.getWidth() - sc.getWidth()) / 2.0;
+            double y = w.getY() + (w.getHeight() - sc.getHeight()) / 2.0;
+            s.setX(x);
+            s.setY(y);
+        }
+    }
